import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Dashboard = ({ schedule, setSchedule }) => {
  const navigate = useNavigate();
  const [syllabus, setSyllabus] = useState('');
  const [targetDate, setTargetDate] = useState('');

  const generateSchedule = () => {
    const topics = syllabus.split(',').map(t => t.trim());
    const newPlan = topics.map((topic, i) => ({
      day: i + 1,
      topic: topic,
      status: 'pending' // Initial status
    }));
    setSchedule(newPlan);
  };

  return (
    <div style={{ padding: '20px', maxWidth: '800px', margin: '0 auto' }}>
      <h2>StudyPulse Dashboard</h2>
      
      {/* Input Section */}
      {!schedule && (
        <div style={{ marginBottom: '30px', display: 'flex', flexDirection: 'column', gap: '10px' }}>
          <input type="date" onChange={(e) => setTargetDate(e.target.value)} />
          <textarea 
            placeholder="Enter topics separated by commas..." 
            onChange={(e) => setSyllabus(e.target.value)}
          />
          <button onClick={generateSchedule} style={{ padding: '10px', background: '#3498db', color: 'white' }}>
            Generate Plan
          </button>
        </div>
      )}

      {/* Persistence List */}
      {schedule && (
        <div>
          <h3>Your Plan:</h3>
          {schedule.map((item) => (
            <div 
              key={item.day}
              onClick={() => navigate(`/study-session/${item.day}`, { state: { topic: item.topic } })}
              style={{ 
                padding: '15px', 
                margin: '10px 0',
                borderRadius: '8px',
                cursor: 'pointer',
                background: item.status === 'completed' ? '#d4edda' : '#fff',
                border: item.status === 'completed' ? '1px solid #c3e6cb' : '1px solid #ddd',
                display: 'flex',
                justifyContent: 'space-between'
              }}
            >
              <span>Day {item.day}: {item.topic}</span>
              <strong>{item.status === 'completed' ? '✅ Done' : '⏳ Pending'}</strong>
            </div>
          ))}
          <button onClick={() => {localStorage.removeItem('studyPulse_Plan'); setSchedule(null);}} style={{marginTop: '20px', color: 'red'}}>Clear Plan & Start New</button>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
